```python
def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    current = []
    balance = 0

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if balance == 0 and current:
                groups.append(''.join(current))
                current = []
            current.append(char)
            balance += 1
        elif char == ')':
            current.append(char)
            balance -= 1

        if balance == 0 and current:
            groups.append(''.join(current))
            current = []

    return groups
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    current_group = []
    balance = 0

    for char in paren_string.replace(' ', ''):
        if char == '(':
            if balance == 0 and current_group:
                groups.append(''.join(current_group))
                current_group = []
            current_group.append(char)
            balance += 1
        elif char == ')':
            current_group.append(char)
            balance -= 1
            if balance == 0:
                groups.append(''.join(current_group))
                current_group = []

    return groups
```

